solutions.python:
class Solution:
    def minCoins(self, coins, n, c):
        dp = [[float('inf') for _ in range(n+1)] for _ in range(c+1)]
        dp[0][0] = 0
        for i in range(1, c+1):
            for j in range(1, n+1):
                if coins[i-1] <= j:
                    dp[i][j] = min(dp[i-1][j], dp[i][j-coins[i-1]] + 1)
                else:
                    dp[i][j] = dp[i-1][j]
        return dp[c][n]

