class Solution {
public:
int minCoins(vector<int>& coins, int n, int c) {
    int dp[c+1][n+1];
    for (int i=0; i<=c; i++) {
        for (int j=0; j<=n; j++) {
            dp[i][j] = (coins[i] <= j) ? min(dp[i-1][j], dp[i][j-coins[i]] + 1) : dp[i-1][j];
        }
    }
    return dp[c][n];
}
};
